#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    string serialize(TreeNode* root) {
        string res;
        function<void(TreeNode*)> dfs = [&](TreeNode* node) {
            if (!node) {
                res += "#,";
                return;
            }
            res += to_string(node->val) + ",";
            dfs(node->left);
            dfs(node->right);
        };
        dfs(root);
        return res;
    }

    TreeNode* deserialize(const string& data) {
        vector<string> tokens;
        string token;
        for (char c : data) {
            if (c == ',') {
                tokens.push_back(token);
                token.clear();
            } else {
                token.push_back(c);
            }
        }
        // tokens may have an extra empty at end if data ends with comma
        int idx = 0;
        function<TreeNode*()> build = [&]() -> TreeNode* {
            if (idx >= (int)tokens.size()) return nullptr;
            string val = tokens[idx++];
            if (val == "#") return nullptr;
            TreeNode* node = new TreeNode(stoi(val));
            node->left = build();
            node->right = build();
            return node;
        };
        return build();
    }

    void inorder(TreeNode* root, vector<int>& out) {
        if (!root) return;
        inorder(root->left, out);
        out.push_back(root->val);
        inorder(root->right, out);
    }
};

TreeNode* buildTree(const vector<int>& vals) {
    if (vals.empty() || vals[0] == -1) return nullptr;
    unordered_map<int, TreeNode*> nodes;
    TreeNode* root = new TreeNode(vals[0]);
    nodes[0] = root;
    queue<int> q;
    q.push(0);
    size_t i = 1;
    while (!q.empty() && i < vals.size()) {
        int idx = q.front(); q.pop();
        TreeNode* cur = nodes[idx];
        // left
        if (i < vals.size()) {
            if (vals[i] != -1) {
                TreeNode* left = new TreeNode(vals[i]);
                cur->left = left;
                nodes[2*idx+1] = left;
                q.push(2*idx+1);
            }
            ++i;
        }
        // right
        if (i < vals.size()) {
            if (vals[i] != -1) {
                TreeNode* right = new TreeNode(vals[i]);
                cur->right = right;
                nodes[2*idx+2] = right;
                q.push(2*idx+2);
            }
            ++i;
        }
    }
    return root;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<int> vals(N);
    for (int i = 0; i < N; ++i) cin >> vals[i];
    TreeNode* root = buildTree(vals);
    Solution sol;
    string ser = sol.serialize(root);
    cout << ser << "\n";
    TreeNode* desRoot = sol.deserialize(ser);
    vector<int> inorderVals;
    sol.inorder(desRoot, inorderVals);
    for (size_t i = 0; i < inorderVals.size(); ++i) {
        if (i) cout << ' ';
        cout << inorderVals[i];
    }
    cout << "\n";
    return 0;
}
